import{_ as c}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as p,c as d,f as r,a as o,b as e,d as a,e as n}from"./app-982f26ff.js";const t={},i=o("blockquote",null,[o("p",null,"省赛配置流程，当做遗产留下来")],-1),B=n('<p>简单划分为几个部分：</p><ol><li>网络环境配置</li><li><code>DOMJudge</code> 的配置</li><li>选手环境配置</li><li>外榜配置</li><li>打印配置</li><li>气球配置</li><li>上传题目（包括 <code>spj</code> 和数据）</li><li>人员配置</li><li>滚榜配置</li></ol><p>一项一项说明吧。</p><h1 id="网络环境配置" tabindex="-1"><a class="header-anchor" href="#网络环境配置" aria-hidden="true">#</a> 网络环境配置</h1><blockquote><p>据说下次可以去一个大场地，那可能这块就用不到了</p></blockquote><p>由于这次省赛比较特殊，要在四个机房打，所以需要把四个机房的局域网给连起来。一开始的设想是在三楼弄个交换机或者路由器，然后把一楼和四楼的交换机都接到这个机器上，这样配置好路由之后就可以互通了。</p><p>但最后没采用这个方案（算是变成备选方案了），更好的方法是找信息化办，让他把网段连起来，这样我们只需要按照他给的 <code>IP</code> 、网关和掩码配置每一台机器就行。</p><blockquote><p>如果是在一个场馆内，那就可以直接配一个交换机。在一个局域网下的，就不存在上述的问题了，一个局域网下可以配253台机器，对于省赛来说应该完全够用了</p></blockquote><p>所以网络环境的配置和我们关系不是很大（</p><blockquote><p><code>2023/05/12</code> 更新</p></blockquote><p>来帮 <code>HEU</code> 配置环境了，人家用的就是一个大场馆（xm T^T），遇到的问题就是需要配置静态 <code>ip</code> ，包括 <code>domjudge</code> 和 打印机 的 <code>ip</code> 地址，这两个必须固定（因为需要打在参赛手册上）</p><h1 id="domjudge-配置" tabindex="-1"><a class="header-anchor" href="#domjudge-配置" aria-hidden="true">#</a> <code>DOMJudge</code> 配置</h1><p>系统默认为 <code>Ubuntu 20.04</code> 或 <code>Ubuntu 22.04</code>，自己弄个U启装吧。</p><p>分为 <code>DOMServer</code> 和 <code>Judgehost</code></p>',14),u={href:"https://github.com/cn-xcpc-tools/cn-xcpc-docs/",target:"_blank",rel:"noopener noreferrer"},y=n(`<p>先给出我们的配置：</p><p>三台 <code>114</code> 机房的机子，一台为服务器(<code>DOMServer</code>)，另外两台为判题机(<code>Judgehost</code>)，机子应该都是十代i5的，16G内存</p><p>因为我们按照上述文档无法直接安装，大概是在下图这一步出了问题</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/image-20230419184735145.png" alt="image-20230419184735145" tabindex="0" loading="lazy"><figcaption>image-20230419184735145</figcaption></figure><p>文档中也没有给出解决方法，只是让你检查（谁知道怎么检查）</p><p>所以我们改用了 <code>docker</code>，下面给出 <code>docker</code> 的配置方法</p><blockquote><p>采用 <code>docker</code> 配置的话，建议和 <code>docker hub</code> 中的文档一起看</p></blockquote><h2 id="docker" tabindex="-1"><a class="header-anchor" href="#docker" aria-hidden="true">#</a> <code>docker</code></h2><p>首先下载 <code>docker</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">apt</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">install</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker-compose</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-y</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>下载完后应该就可以拉取镜像了，文档中说更换镜像源这一步可做可不做（当时是没做，下载的也挺快的，所以建议用 <code>NENUAF</code> 这个网络下载）</p><blockquote><p>更新，在 <code>HEU</code> 这没拉下来，可能还是需要改镜像的，我直接把东西复制过来吧</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">mkdir</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-p</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/etc/docker</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">tee</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/etc/docker/daemon.json</span><span style="color:#ABB2BF;"> &lt;&lt;-&#39;</span><span style="color:#ABB2BF;">EOF</span><span style="color:#ABB2BF;">&#39;</span></span>
<span class="line"><span style="color:#98C379;">{</span></span>
<span class="line"><span style="color:#98C379;">    &quot;registry-mirrors&quot;: [</span></span>
<span class="line"><span style="color:#98C379;">        &quot;https://reg-mirror.qiniu.com&quot;,</span></span>
<span class="line"><span style="color:#98C379;">        &quot;https://mirror.ccs.tencentyun.com&quot;,</span></span>
<span class="line"><span style="color:#98C379;">        &quot;http://hub-mirror.c.163.com&quot;</span></span>
<span class="line"><span style="color:#98C379;">    ]</span></span>
<span class="line"><span style="color:#98C379;">}</span></span>
<span class="line"><span style="color:#ABB2BF;">EOF</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">systemctl</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">daemon-reload</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">systemctl</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">restart</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><h2 id="domserver" tabindex="-1"><a class="header-anchor" href="#domserver" aria-hidden="true">#</a> <code>DOMServer</code></h2><ol><li><p>拉取 <code>MariaDB</code> ，下面给出一些坑点和解释</p><ul><li><p><code>MYSQL_ROOT_PASSWORD</code> 和 <code>MYSQL_PASSWORD</code> 一定要确保后续命令中的相关项与其所对应的值一致。具体的值可以随机生成一组强度足够的密码。</p></li><li><p>MySQL 创建用户 <code>domjudge</code> ，密码对应 <code>[passwd2]</code> ，root 密码对应 <code>[passwd1]</code> （这俩都不是很重要，反正我没用过这俩）</p></li><li><p>容器时区设置为 <code>Asia/Shanghai</code> ，容器外部数据库端口设置为 <code>13306</code></p></li><li><p>设置了<code>--max-connections</code>为<code>1000</code>，保证能够顺利进行数据库连接</p></li><li><p>设置了<code>--max-allowed-packet</code>为<code>1GB</code>，<strong>特别注意，底层单位为<code>B</code>，而不是<code>KB</code></strong>。此外，貌似你设置的值大于1GB，就会按照1GB来计算。此处的值主要取决于你最大的测试数据点，一般选为<strong>最大测试点的两倍</strong>。</p></li><li><p>设置了<code>--innodb-log-file-size</code>为<code>5GB</code>，单位同上。此处的值同样主要取决于你最大的测试数据点，一般选为<strong>最大测试点的十倍</strong>。此外，该变量与上面的不同，需要重启数据库才能更改，因此如果你<strong>使用docker部署数据库</strong>，请务必在启用时就做好参数的指定，所以建议设大点，我们设了5 GB。</p></li><li><p>上面指标这些是否达标，可以在 <code>domjudge</code> 管理端的右侧部分一个 <code>check config</code> 里面查看（大概是叫这个名字）</p></li></ul><p><strong>特别注意，设置 MariaDB 密码不能有特殊字符（最好是大小写字母加数字，否则会搭建失败）。</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--name</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">dj-mariadb</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_ROOT_PASSWORD=[passwd1]</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_USER=domjudge</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">CONTAINER_TIMEZONE=Asia/Shanghai</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_PASSWORD=[passwd2]</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_DATABASE=domjudge</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-p</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">13306</span><span style="color:#98C379;">:3306</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">mariadb</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--max-connections=1000</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--max-allowed-packet=1GB</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--innodb-log-file-size=5GB</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>拉取 <code>DOMServer</code> ，给出一些参数解释</p><ul><li><code>MYSQL_ROOT_PASSWORD</code> 和 <code>MYSQL_PASSWORD</code> 一定要第一条命令中的值一致。</li><li>这里默认拉取的是最新版本的 <code>domserver</code> ，注意版本要和下面的 <code>judgehost</code> 一致，因此最好的方法就是直接不指定版本。</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--link</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">dj-mariadb:mariadb</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_HOST=mariadb</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_USER=domjudge</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_DATABASE=domjudge</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">CONTAINER_TIMEZONE=Asia/Shanghai</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_PASSWORD=[passwd2]</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">MYSQL_ROOT_PASSWORD=[passwd1]</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-p</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">80</span><span style="color:#98C379;">:80</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--name</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">domserver</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">domjudge/domserver</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>容器建立完后，可能会跑不起来，那么我们需要：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">ps</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-a</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>找到 <code>DOMServer</code> 容器的编号，例如编号为 <code>ce214ewasnh1o</code>，那么我们输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">ce</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>即可成功启动</p></li><li><p>一开始启动失败的话，我们是看不见 <code>admin</code> 密码和 <code>judgehost</code> 的密码的，因此我们需要输入</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">exec</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">domserver</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">cat</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/opt/domjudge/domserver/etc/initial_admin_password.secret</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">exec</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">domserver</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">cat</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/opt/domjudge/domserver/etc/restapi.secret</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>第一个是 <code>admin</code> 的初始密码（应该会很复杂，建议保存在 <code>txt</code> 文件里），第二个是下面配置 <code>judgehost</code> 需要的 <code>api key</code> ，都需要保存好。</p></li></ol><p>配置完成后，本机输入 <code>localhost</code> 应该能够直接访问 <code>DOMServer</code> 的页面了（也可以登录干啥的，就是不能交题）</p><h2 id="judgehost" tabindex="-1"><a class="header-anchor" href="#judgehost" aria-hidden="true">#</a> <code>Judgehost</code></h2><p>在开始部署之前，需要修改 <code>grub</code></p><p>请编辑<code>/etc/default/grub</code>，修改：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#E06C75;">GRUB_CMDLINE_LINUX_DEFAULT</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;quiet cgroup_enable=memory swapaccount=1&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>当然这个可能也会有问题，那么可以修改成</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#E06C75;">GRUB_CMDLINE_LINUX_DEFAULT</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;quiet cgroup_enable=memory swapaccount=1 systemd.unified_cgroup_hierarchy=0&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后更新 <code>grub</code> 并重启</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">update-grub</span></span>
<span class="line"><span style="color:#61AFEF;">reboot</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>结束后可以开始配置 <code>judgehost</code></p><p>给出一些命令解释：</p><ul><li>容器名为 <code>judgehost-0</code> ，判题机命名为 <code>judgedaemon-0</code> ，对应ID为 <code>0</code> ，<code>JUDGEDAEMON_PASSWORD</code> 要确保与上面获得的 <code>jusgehost</code> 的账号密码一致，容器时区设置为 <code>Asia/Shanghai</code> 。</li><li><code>DOMSERVER_BASEURL</code> 是服务器的 <code>IP</code> 地址，所以这个 <code>Judgehost</code> 是要等服务器确定 <code>IP</code> 后才能部署的（部署也快，不用着急），记得要在一个局域网下才能连接。</li></ul><blockquote><p>更新， 必须要知道 <code>domserver</code> 的 <code>ip</code> 才能配置 <code>judgehost</code>，否则会报错无法连接 <code>localhost</code> 的 80 端口，我猜测这是因为 <code>docker</code> 把 <code>localhost</code> 认为是 <code>docker</code> 自己的 <code>localhost</code> 而不是主机 <code>host</code> 的 <code>localhost</code></p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">run</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-it</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--privileged</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-v</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">/sys/fs/cgroup:/sys/fs/cgroup:ro</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--name</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">judgehost-0</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--hostname</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">judgedaemon-0</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">DAEMON_ID=</span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">JUDGEDAEMON_PASSWORD=xxxxxxx</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">DOMSERVER_BASEURL=http://192.168.1.251/</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-e</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">CONTAINER_TIMEZONE=Asia/Shanghai</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">domjudge/judgehost</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注意这个可能会报错，说什么无法在<code>/sys/fs/cgroup/cpuset</code> 创建目录，什么只读什么，然后说让你更改 <code>grub</code> 那个文件（上面写的那种），如果你已经改好了（指改成第二种），那随便了，这个可能是抽风了，直接</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">ps</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-a</span></span>
<span class="line"><span style="color:#61AFEF;">sudo</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">docker</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">xxx</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>xxx</code> 是容器编号，启动就行</p><p>如果没改那就改完然后重启，然后 <code>sudo docker start xxx</code></p><p>启动成功后，可以在 <code>DOMServer</code> 的 <code>judgehost</code> 里面找到你配置好的东西，名字和 <code>--hostname</code> 一样。</p><p><strong>注意如果要开启多个的话，需要保证 <code>--name</code> 、<code>--hostname</code> 、<code>DAEMON_ID</code> 为不重复关键字。</strong></p><blockquote><p>这次我们就开了五个，一台机器开三个，一台机器开两个，服务器一个都没开，因为服务器压力不能太大，怕网络请求直接把服务器干碎了（</p><p>五个评测机完全够用了（甚至可能还多了</p><p><code>ps</code> 我们这次只有 164 个队伍参赛</p></blockquote><p>文档中说了，也不能开太多评测机，不然对服务器压力也很大，所以五个也差不多了（</p><p>然后最新版本的 <code>judgehost</code> 是支持 <code>python</code> 提交的，不需要按照文档说的去更改 <code>chroot</code> 然后安装。</p><p>最后给出判题环境各个语言编译器的版本：</p><ul><li><code>C</code>: <code>gcc 10.2.1</code></li><li><code>C++</code>: <code>g++ 10.2.1</code></li><li><code>Java</code>: <code>openjdk 11.0.12</code></li><li><code>python</code>: <code>python3.9</code></li></ul><p>注意这里 <code>C/C++</code> 默认开的 <code>O2</code> 优化，<code>C++</code> 没加 <code>-std=11</code>，所以应该是支持部分 <code>C++17</code> 标准的（反正肯定支持 <code>C++14</code>，也就是说可以用 <code>auto</code> 和 <code>for(auto s: v)</code> 这种遍历 <code>STL</code> 的方式）</p><h1 id="选手环境配置" tabindex="-1"><a class="header-anchor" href="#选手环境配置" aria-hidden="true">#</a> 选手环境配置</h1><p>选手比赛用机选用的是 <code>ICPC 2023 WF</code> 的镜像，环境为：</p><ul><li><code>C/C++</code>: <code>ICPC-Clion 2022.3</code>, <code>Code::Blocks 20.03</code></li><li><code>Java</code>: <code>Eclipse 2022-12</code>, <code>ICPC-Idea Community 2022.3</code></li><li><code>Python</code>: <code>Geany 1.38</code>, <code>ICPC-PyCharm Community 2022.3</code></li></ul><p>比赛用机上的 <code>Java</code> 环境是 <code>openjdk-17</code> ，和判题环境不一样，一切以判题环境为准（17 兼容 11，而且我觉得也不太会有人写 <code>Java</code>.... ）</p>`,44),h=o("code",null,"2024",-1),m={href:"https://image.icpc.global/icpc2023/ImageBuildInstructions.html",target:"_blank",rel:"noopener noreferrer"},A=o("p",null,[e("有了 U启 之后就是装机了，我们是一台一台装过去的，但是我看机房电脑的 "),o("code",null,"BIOS"),e(" 好像支持 "),o("code",null,"PXE"),e(" 传系统，应该是可以同传的，不需要一台一台传过去。。。")],-1),b=o("code",null,"PXE",-1),g={href:"https://www.zhihu.com/tardis/zm/art/374054171?source_id=1005",target:"_blank",rel:"noopener noreferrer"},v=n(`<p>如果不行的话，那就花一天时间装机器，装机流程如下（提前需要把每个人要装的机器的 <code>ip</code>，网关，掩码都打印出来，弄成表发下去）</p><blockquote><p>壁纸在每个U盘里面，就是那个 <code>desktop.jpg</code> 的图片，如果有新壁纸，请提前替换这个文件</p></blockquote><h2 id="装机流程" tabindex="-1"><a class="header-anchor" href="#装机流程" aria-hidden="true">#</a> 装机流程</h2><p>分为</p><ol><li><p>装 Ubuntu 系统</p></li><li><p>设置桌面</p></li><li><p>手动设置 IP 地址</p></li></ol><h3 id="装ubuntu" tabindex="-1"><a class="header-anchor" href="#装ubuntu" aria-hidden="true">#</a> 装Ubuntu</h3><p><strong>开机前先插上U盘</strong></p><p>开机后，一直按 <code>F12</code> 直到进入 <code>BIOS</code> 界面，回车选择 <code>USB HDD</code> 中的选项（可能会有两个分区，选择任意一个都可以）</p><p>选择后会自动进入一个黑框页面，回车进第一个 <code>Ubuntu</code> 选项，之后能看见 <code>ICPC WF</code> 的桌面。</p><p>然后会弹出一个安装界面，安装步骤如下：</p><ol><li><p>选择语言：中文（简体）</p></li><li><p>点击右侧的 “安装Ubuntu”</p></li><li><p>键盘布局：不需要修改，直接点击右下方的 “继续”</p></li><li><p>更新和其他软件：选择 “最小安装”，点击下方的 “继续”</p></li><li><p>安装类型：选择 “清除整个磁盘并安装Ubuntu”，点击右下方的 ”现在安装“</p></li><li><p>后续一路点击 ”继续“ 即可</p></li><li><p>您是谁：</p><ol><li><p>姓名：这台电脑的 IP 地址（需要自己设置静态 IP，查表找）</p></li><li><p>计算机名：统一设置为 ubuntu-xxx （xxx为上述ip地址的后两段，例如ip地址为 222.27.111.3，那这里就是ubuntu-111.3）</p></li><li><p>用户名：ubuntu</p></li><li><p>密码：0</p></li><li><p>选择 ”自动登录“</p></li></ol><p>点击 ”继续“</p></li><li><p>等待安装结束</p></li></ol><p>安装结束后点击 ”现在重启“ 即可</p><h3 id="设置桌面" tabindex="-1"><a class="header-anchor" href="#设置桌面" aria-hidden="true">#</a> 设置桌面</h3><p>重启的时候需要敲一下回车键，然后就能重启完成。</p><p>将 U 盘重新插入</p><p>打开桌面上的主目录，点击左侧的 ICPC World Final 那个U盘，里面有一张 .jpg 格式的图片，右键图片，选择 “设为壁纸” 即可</p><h3 id="设置-ip-地址" tabindex="-1"><a class="header-anchor" href="#设置-ip-地址" aria-hidden="true">#</a> 设置 IP 地址</h3><ol><li><p>按 <code>Ctrl</code> + <code>Alt</code> + <code>T</code> 打开终端，输入 <code>sudo su</code> ，这一步会要求输入密码，输入 <code>0</code> 回车即可</p></li><li><p>输入 <code>cp /media/ubuntu/ICPC\\ World\\ Finals\\ 2023/network-manager* ~</code></p></li><li><p>输入 <code>cp /media/ubuntu/ICPC\\ World\\ Finals\\ 2023/lib* ~</code></p></li><li><p>输入 <code>cd ~</code></p></li><li><p>输入 <code>dpkg -i lib*</code></p></li><li><p>输入 <code>dpkg -i network-manager*</code></p></li><li><p>输入 <code>gedit /etc/network/interfaces.d/</code> 然后按 tab 即可（<code>tab</code> 键会自动补全，在输入上面的路径时也可以按 <code>tab</code> 进行补全），默认的路径是 <code>/etc/network/interfaces.d/enp1s0</code></p></li><li><p>打开文件后，将文件更改为如下格式：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#98C379;">allow-hotplug enp1s0</span></span>
<span class="line"><span style="color:#98C379;">iface enp1s0 inet static</span></span>
<span class="line"><span style="color:#98C379;">address x.x.x.x</span></span>
<span class="line"><span style="color:#98C379;">gateway x.x.x.x</span></span>
<span class="line"><span style="color:#98C379;">netmask x.x.x.x</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><p>注意上面的 <code>enp1s0</code> 是根据电脑所打开的文件名确定的，注意可能会不一样</p><p>所有的 <code>x.x.x.x</code> 都查表看即可</p><ol start="4"><li><p>保存该文件后关闭</p></li><li><p>在终端输入 <code>gedit /etc/netplan/01-network-manager-all.yaml</code></p></li><li><p>打开文件后，将文件更改为如下格式：</p></li></ol><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#E06C75;">network</span><span style="color:#ABB2BF;">:</span></span>
<span class="line"><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">version</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">2</span></span>
<span class="line"><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">renderer</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">NetworkManager</span></span>
<span class="line"><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">ethernets</span><span style="color:#ABB2BF;">:</span></span>
<span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#E06C75;">enp1s0</span><span style="color:#ABB2BF;">:</span></span>
<span class="line"><span style="color:#ABB2BF;">     </span><span style="color:#E06C75;">dhcp4</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">false</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="7"><li><p>保存后关闭文件</p></li><li><p>输入 <code>netplan apply</code></p></li><li><p>输入 <code>systemctl restart NetworkManager</code></p></li><li><p>输入 <code>reboot</code> 等待重启</p></li><li><p>输入 <code>ip a</code> 查看是否生效</p></li></ol><h1 id="外榜配置" tabindex="-1"><a class="header-anchor" href="#外榜配置" aria-hidden="true">#</a> 外榜配置</h1><h2 id="内网榜单" tabindex="-1"><a class="header-anchor" href="#内网榜单" aria-hidden="true">#</a> 内网榜单</h2><p>假设现在 <code>DOMServer</code> 配置在 <code>IP</code> 为 <code>222.27.110.245</code> 上面，那么局域网内直接访问：</p><p><code>http://222.27.110.245/public?static=true&amp;contest={cid}</code>，其中 <code>{cid}</code> 为比赛的编号，例如 <code>5</code> ，可以直接看见 <code>cid</code> 为 <code>5</code> 的比赛的静态榜单。</p><blockquote><p>在 <code>DOMServer</code> 中看 <code>cid</code> 可能不是 <code>5</code> 而是 <code>c5</code>……，但其实他就是 <code>5</code></p></blockquote><h2 id="外网榜单" tabindex="-1"><a class="header-anchor" href="#外网榜单" aria-hidden="true">#</a> 外网榜单</h2>`,29),F={href:"https://github.com/ehang-io/nps",target:"_blank",rel:"noopener noreferrer"},C={href:"https://github.com/ehang-io/nps/blob/master/README_zh.md",target:"_blank",rel:"noopener noreferrer"},k=o("code",null,"IP",-1),x=n('<p>装上无线网卡会导致以太网失灵，这是因为这两个网关都默认监听 <code>0.0.0.0</code> （也就是所有网段），解决方案是更改服务器的路由：</p><p>让无线网监听 <code>0.0.0.0</code> ，让以太网的网关监听局域网的网段，例如现在局域网段为 <code>222.27.110.0</code>，把这个加进路由表，让服务器监听即可</p><p>假设现在公网 <code>ip</code> 是 <code>43.125.12.154</code>，穿刺过来的端口是 <code>6666</code>，那么静态榜单的地址就是：</p><p><code>http://43.125.12.154:6666/public?static=true&amp;contest={cid}</code></p><p>这样是不安全的，因为可能有人直接把后面那一堆去掉，然后就可以登录帮人答题了（</p><p>最好的方法是用域名隐藏这些东西，然后在服务器上用 <code>nginx</code> 进行反代，注意 <code>?</code> 后面那些都是 <code>GET</code> 请求的 <code>query</code> 参数，可能需要看看 <code>nginx</code> 文档然后再去写配置文件。</p><blockquote><p>我们用的方法是半小时后开外榜，因为半小时后教练已经拿到题了……这个问题就没那么重要了（</p><p>但有时间的话，最好还是解决一下，让外网通过一个域名就能直接访问（或者划两个子域名出来给两个比赛）</p></blockquote><h1 id="打印配置" tabindex="-1"><a class="header-anchor" href="#打印配置" aria-hidden="true">#</a> 打印配置</h1><p><code>DOMJudge</code> 我没找到打印的功能，但是看文档好像可以用 <code>enscript</code> 这个打印？但我觉得这个好像只是生成pdf……，也没有直接的打印服务，所以就直接用 <code>flask</code> 先写了一个简陋能用的打印服务。</p><blockquote><p>好像说这个代码没法控制行间距，所以导致行间距太大，一份长一点的代码就是好几页，也不好看，准备这段时间改改……（跑路了）</p></blockquote>',10),_={href:"https://github.com/topdeoo/CodePrint",target:"_blank",rel:"noopener noreferrer"},D=n('<p>使用的过程在项目的 <code>README</code> 中都有描述，此处略过。</p><h1 id="气球配置" tabindex="-1"><a class="header-anchor" href="#气球配置" aria-hidden="true">#</a> 气球配置</h1><p>开两个气球账号（ <code>DOMJudge</code> 自带的功能，不需要用 <code>ICPC Tools</code> 了），一个在正常的浏览器里面登录，另外一个需要浏览器开无痕浏览（为的是需要不一样的 <code>cookies</code> ）然后登陆，这样就可以实现一个账号看一个比赛了。</p><p>里面的功能还是比较全的，可以看一血，可以点击标记是否送过气球（设备都同步的），具体的用法应该在场馆都会有安排，这里不解释了。</p><h1 id="上传" tabindex="-1"><a class="header-anchor" href="#上传" aria-hidden="true">#</a> 上传</h1><h2 id="数据的上传" tabindex="-1"><a class="header-anchor" href="#数据的上传" aria-hidden="true">#</a> 数据的上传</h2><p>按照文档来就是，这个不归我们管，让出题的来弄就行，需要提醒的可能就是只能用 <code>winrar</code> 压成 <code>zip</code> 然后才能上传成功，不知道是怎么设计的（，可能是在给 <code>WinRAR</code> 打广告吧</p><h2 id="学校和队伍的上传" tabindex="-1"><a class="header-anchor" href="#学校和队伍的上传" aria-hidden="true">#</a> 学校和队伍的上传</h2><p>上传的步骤：</p><ol><li><code>team affiliations</code></li><li><code>team categories</code></li><li><code>teams</code></li></ol>',10),E={href:"https://www.domjudge.org/docs/manual/8.2/import.html#importing-accounts",target:"_blank",rel:"noopener noreferrer"},f=n(`<p>注意可能用的 <code>json</code> 文件，并且使用命令行上传</p><blockquote><p>最后需要注意， <code>team</code> 的 <code>location</code> 需要自己手动输入（因为数据库是 <code>docker</code> 装的，所以导致没办法直接用语句导入，也可能可以？但是我不会……）</p></blockquote><blockquote><p>注意，队伍上传时有一个参数的队伍的分类，建议是先建立分类，再上传队伍。</p><p>这次比赛建立的分类是：</p><ol><li><code>AGroup</code></li><li><code>BGroup</code></li><li><code>StarTeam</code></li><li><code>WomenTeam_AGroup</code></li><li><code>WomenTeam_BGroup</code></li></ol></blockquote><p>创建比赛时，可以选择不开放给所有队伍，开放给指定分类的队伍（可多选）</p><h1 id="人员配置" tabindex="-1"><a class="header-anchor" href="#人员配置" aria-hidden="true">#</a> 人员配置</h1><blockquote><p>请注意，打印服务和 <code>OJ</code> 的地址一定要说清楚，已经两次经典复现了，跑去打印的网址登录 <code>OJ</code>，然后导致这边打印出来一堆废纸（</p></blockquote><p><strong>热身赛当天，知道怎么调IDE的，怎么调编译器的，怎么用终端的，怎么命令行编译的人一定要多一点</strong></p><p>热身赛应该是最忙的时候了，因为大家都在熟悉比赛环境，人太少了会忙不过来，无时无刻都会有问题……</p><p>而且问题都会问的很抽象……让人感觉都是没写过代码的人问的问题……（也可能是没用过 <code>Clion</code> ?）</p><p>正赛的时候会好很多，大家都不咋问技术问题了。</p><p>这里写一些<strong>热身赛</strong>时我遇到的人家问的问题：</p><ol><li><p><code>Code::Blocks</code> 有问题，没办法编译运行，提示没有配置 <code>gcc/g++</code></p><p>解决方法：帮他配置 <code>gcc/g++</code> ，或者让他直接改用 <code>Clion</code></p></li><li><p><code>Clion</code> 无法编译运行</p><p>解决方法：一般来说不可能，出现这种情况一般是 <code>CMakeList.txt</code> 没写对，比如除了原来的 <code>main.cpp</code> 之外又加了一个含有 <code>main</code> 函数的 <code>.cpp</code> 文件，改一下 <code>CMakeList.txt</code> 就行；第二种情况是右上角的构建没选对，选成了 <code>Build All</code> ，应该换成 <code>CMakeList.txt</code> 里面的项目名称，一般来说都是 <code>ClionProject</code> 。</p></li><li><p>有没有 <code>js</code> 编辑器</p><p>解决方法：退赛</p></li><li><p><code>Idea</code> 无法执行 <code>Java</code> 代码</p><p>解决方法：一般来说都是因为 <code>jdk</code> 配置不对，似乎镜像中 <code>Idea</code> 配置的是 <code>jdk8</code> 还是 <code>11</code>，但环境中用的是 <code>17</code> ，针对这种情况直接新建一个项目即可。</p></li><li><p><code>VS Code</code> 怎么运行 <code>c/cpp</code> 文件</p><p>解决方法：换用 <code>Clion</code>；如果不愿意，那就命令行运行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">gcc</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">xxx.c</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-o</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">xxx</span></span>
<span class="line"><span style="color:#61AFEF;">./xxx</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>xxx</code> 为文件名，如果是 <code>cpp</code>，把 <code>gcc</code> 换成 <code>g++</code> ，文件名换掉就行。</p><p>必须要提醒参赛人员的是，使用命令行的话就必须要会 <code>gdb</code> 调试，因为 <code>VS Code</code> 没有任何插件，没办法进行调试</p></li></ol><p>没遇到大佬用 <code>Vim</code> 或者 <code>Emacs</code> 的，可惜了（</p><p>接下来是<strong>正赛</strong>的时候可能会遇到的问题：</p><ol><li><p><code>Clion</code> / <code>Idea</code> / <code>PyChram</code> 打不开了</p><p>解决方法：按理来说这种应该是前一天删除的时候，有人把整个用户目录都删了，导致密钥没了，最好的方法是直接换台备用机（</p></li><li><p>提交 <code>Java</code> 代码返回 <code>Info: using main from Main</code> 或者什么 <code>from Main</code> ，然后报了 <code>WA</code>，会认为判题系统出问题了或者怎么样</p><p>解决方法：判题系统没有任何问题，注意返回的是 <code>Info</code> 而不是 <code>Error</code> ，而且报的是 <code>WA</code> 而不是 <code>CE</code> ，所以直接说系统没问题就行。</p></li><li><p>判题返回 <code>No Output</code>，但是他觉得自己写了输出语句认为系统有问题</p><p>解决方法：系统没问题，直接 <code>No Comment</code> 就行。</p></li></ol><p>当然还看遇到其他各种各样的，我可能忘记了很多……不过一般都比较好解决，就是可能会觉得问题比较抽象……</p><h1 id="滚榜配置" tabindex="-1"><a class="header-anchor" href="#滚榜配置" aria-hidden="true">#</a> 滚榜配置</h1>`,17),S={href:"https://github.com/cn-xcpc-tools/cn-xcpc-docs/blob/master/resolver.md",target:"_blank",rel:"noopener noreferrer"},O=o("p",null,"队伍或者提交比较多的话，可能会很占内存，所以建议不要用太垃圾的机子跑（今年就卡住了两次……",-1);function M(I,q){const s=l("ExternalLinkIcon");return p(),d("div",null,[i,r("more"),B,o("p",null,[e("配置文档参考了 "),o("a",u,[e("xcpc-docs"),a(s)]),e(" 但并不是完全用这个的")]),y,o("p",null,[e("这个环境感觉很豪华了，"),h,e(" 年应该是不需要修改的，不用修改的U盘应该都留在老师那里了，如果到后面需要修改里面的镜像文件了（重做U启），参考网站为："),o("a",m,[e("ICPC-iso"),a(s)]),e(" （根据年份修改网页就行）")]),A,o("p",null,[e("关于 "),b,e(" 的可以看这里 "),o("a",g,[e("pxe"),a(s)]),e("，我觉得到时候可以试试看，我们是因为时间太紧张了，机房还要上课，没时间测试这个东西……")]),v,o("p",null,[e("让服务器装上无线网卡，然后做内网穿刺，工具为："),o("a",F,[e("nps"),a(s)]),e("，具体配置可以看 "),o("a",C,[e("nps-docs"),a(s)]),e(" 里面的第二条(需要你有一个服务器，因为需要公网 "),k,e(")")]),x,o("p",null,[e("代码的地址："),o("a",_,[e("GitHub - topdeoo/CodePrint: A simple and ungly(?) code print service for XCPC"),a(s)])]),D,o("p",null,[e("上传的格式可以参见文档："),o("a",E,[e("https://www.domjudge.org/docs/manual/8.2/import.html#importing-accounts"),a(s)])]),f,o("p",null,[o("a",S,[e("ICPC-resolver"),a(s)]),e(" 参见文档")]),O])}const w=c(t,[["render",M],["__file","Intro-To-Provincial-Contest.html.vue"]]);export{w as default};
